/**
 * Dictionary Resolver - Resolve @dictionary.keys in section data
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

import { loadTranslations, getNestedValue } from './translations';
import { SupportedLanguage, defaultLanguage } from './config';

/**
 * تشخیص اینکه آیا یک مقدار کلید دیکشنری است
 */
export function isDictionaryKey(value: any): boolean {
  return typeof value === 'string' && value.startsWith('@');
}

/**
 * Resolve کردن یک کلید دیکشنری به متن واقعی
 * @param key - کلید دیکشنری (مثلاً "@sections.hero.title")
 * @param language - زبان مورد نظر
 * @returns متن ترجمه شده یا خود کلید در صورت عدم یافتن
 */
export async function resolveDictionaryKey(
  key: string,
  language: SupportedLanguage = defaultLanguage
): Promise<string> {
  if (!isDictionaryKey(key)) {
    return key;
  }

  try {
    // حذف @ از ابتدا
    const cleanKey = key.substring(1);
    
    // تقسیم به namespace و path
    // مثال: "sections.hero.title" → namespace: "sections", path: "hero.title"
    const parts = cleanKey.split('.');
    const namespace = parts[0];
    const path = parts.slice(1).join('.');

    // بارگذاری ترجمهها
    const translations = await loadTranslations(language, namespace);
    
    // دریافت مقدار
    const value = getNestedValue(translations, path);
    
    // اگر پیدا نشد، fallback به زبان پیشفرض
    if (value === path && language !== defaultLanguage) {
      const defaultTranslations = await loadTranslations(defaultLanguage, namespace);
      return getNestedValue(defaultTranslations, path);
    }
    
    return value;
  } catch (error) {
    console.warn(`Failed to resolve dictionary key: ${key}`, error);
    return key; // بازگشت خود کلید در صورت خطا
  }
}

/**
 * Resolve کردن یک فیلد که ممکن است string ساده یا dictionary key باشد
 * @param value - مقدار فیلد
 * @param language - زبان مورد نظر
 * @returns متن نهایی
 */
export async function resolveFieldValue(
  value: any,
  language: SupportedLanguage = defaultLanguage
): Promise<string> {
  // اگر null یا undefined
  if (value == null) {
    return '';
  }

  // اگر string است
  if (typeof value === 'string') {
    // اگر dictionary key است
    if (isDictionaryKey(value)) {
      return await resolveDictionaryKey(value, language);
    }
    // string ساده
    return value;
  }

  // اگر object است (برای آینده - multilang object)
  if (typeof value === 'object' && value[language]) {
    return value[language];
  }

  // سایر موارد
  return String(value);
}

/**
 * Resolve کردن تمام فیلدهای یک object به صورت recursive
 * @param data - object داده
 * @param language - زبان مورد نظر
 * @returns object با مقادیر resolve شده
 */
export async function resolveObjectFields(
  data: Record<string, any>,
  language: SupportedLanguage = defaultLanguage
): Promise<Record<string, any>> {
  const resolved: Record<string, any> = {};

  for (const [key, value] of Object.entries(data)) {
    if (Array.isArray(value)) {
      // اگر آرایه است، هر عنصر را resolve کن
      resolved[key] = await Promise.all(
        value.map(item => 
          typeof item === 'object' && item !== null
            ? resolveObjectFields(item, language)
            : resolveFieldValue(item, language)
        )
      );
    } else if (typeof value === 'object' && value !== null) {
      // اگر object است، recursive resolve کن
      resolved[key] = await resolveObjectFields(value, language);
    } else {
      // فیلد ساده
      resolved[key] = await resolveFieldValue(value, language);
    }
  }

  return resolved;
}

/**
 * Batch resolve کردن چند کلید دیکشنری
 * @param keys - آرایه کلیدها
 * @param language - زبان مورد نظر
 * @returns object با کلیدها و مقادیر resolve شده
 */
export async function resolveDictionaryKeys(
  keys: string[],
  language: SupportedLanguage = defaultLanguage
): Promise<Record<string, string>> {
  const results: Record<string, string> = {};

  await Promise.all(
    keys.map(async (key) => {
      results[key] = await resolveDictionaryKey(key, language);
    })
  );

  return results;
}
